#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=510,Mod=1e9+7;int dp[N][N][6];char s[N];
int main()
{
	int n=read(),k=read();scanf("%s",s+1);
	rep(1,n,i)dp[i][i-1][0]=1;
	rep(1,n,T)
	{
		for(int l=1,r=T;r<=n;++l,++r)
		{
			if(T<=k&&dp[l][r-1][0]&&(s[r]=='*'||s[r]=='?'))dp[l][r][0]=1;
			if(T>1)
			{
				if((s[l]=='('||s[l]=='?')&&(s[r]==')'||s[r]=='?'))
					dp[l][r][1]=(0ll+dp[l+1][r-1][0]+dp[l+1][r-1][2]+dp[l+1][r-1][3]+dp[l+1][r-1][4])%Mod;
				rep(l,r-1,i)
				{
					dp[l][r][2]+=1ll*dp[l][i][3]*dp[i+1][r][0]%Mod;dp[l][r][2]>Mod?dp[l][r][2]-=Mod:0;
					dp[l][r][3]+=1ll*(dp[l][i][2]+dp[l][i][3])*dp[i+1][r][1]%Mod;dp[l][r][3]>Mod?dp[l][r][3]-=Mod:0;
					dp[l][r][4]+=1ll*(dp[l][i][4]+dp[l][i][5])*dp[i+1][r][1]%Mod;dp[l][r][4]>Mod?dp[l][r][4]-=Mod:0;
					dp[l][r][5]+=1ll*dp[l][i][4]*dp[i+1][r][0]%Mod;dp[l][r][5]>Mod?dp[l][r][5]-=Mod:0;
				}
			}
			dp[l][r][5]+=dp[l][r][0];dp[l][r][5]>Mod?dp[l][r][5]-=Mod:0;
			dp[l][r][3]+=dp[l][r][1];dp[l][r][3]>Mod?dp[l][r][3]-=Mod:0; 
		}
	}
	printf("%d\n",dp[1][n][3]);
}
